{
  "name": "NovaStream AI Music",
  "description": "A high-end music streaming experience featuring AI-powered mood curation, lyrical analysis, and dynamic audio visualization powered by Gemini.",
  "requestFramePermissions": [
    "microphone"
  ]
}

export interface Track {
  id: string;
  title: string;
  artist: string;
  album: string;
  duration: string;
  coverUrl: string;
  audioUrl: string;
  genre: string;
  description?: string;
}

export interface Playlist {
  id: string;
  name: string;
  description: string;
  tracks: Track[];
  coverUrl: string;
}

export enum ViewState {
  HOME = 'home',
  PLAYLIST = 'playlist',
  AI_EXPLORER = 'ai_explorer',
  LYRICS = 'lyrics'
}

export interface AIRecommendation {
  title: string;
  artist: string;
  reason: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIRecommendation } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getMoodPlaylist = async (mood: string): Promise<AIRecommendation[]> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest a 5-song playlist based on the mood: "${mood}". For each song, provide a title, artist, and a brief reason why it fits.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            artist: { type: Type.STRING },
            reason: { type: Type.STRING }
          },
          required: ["title", "artist", "reason"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || '[]');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return [];
  }
};

export const explainSong = async (title: string, artist: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Explain the meaning and history of the song "${title}" by ${artist}. Include interesting trivia and its impact on culture. Keep it around 200 words.`,
  });
  return response.text || "No explanation available.";
};

export const generateLyrics = async (mood: string, genre: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Write song lyrics for a ${genre} song that feels ${mood}. Include a Verse, Chorus, and Bridge.`,
  });
  return response.text || "Error generating lyrics.";
};

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface VisualizerProps {
  isPlaying: boolean;
  audioRef: React.RefObject<HTMLAudioElement>;
}

const Visualizer: React.FC<VisualizerProps> = ({ isPlaying, audioRef }) => {
  const canvasRef = useRef<SVGSVGElement>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const dataArrayRef = useRef<Uint8Array | null>(null);
  const animationIdRef = useRef<number>();

  useEffect(() => {
    if (!audioRef.current || !canvasRef.current) return;

    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    const analyser = audioContext.createAnalyser();
    const source = audioContext.createMediaElementSource(audioRef.current);

    source.connect(analyser);
    analyser.connect(audioContext.destination);

    analyser.fftSize = 128;
    const bufferLength = analyser.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    analyserRef.current = analyser;
    dataArrayRef.current = dataArray;

    const svg = d3.select(canvasRef.current);
    const width = 300;
    const height = 150;

    const renderFrame = () => {
      if (!isPlaying) {
        animationIdRef.current = requestAnimationFrame(renderFrame);
        return;
      }

      analyser.getByteFrequencyData(dataArray);

      svg.selectAll('rect')
        .data(Array.from(dataArray))
        .join('rect')
        .attr('x', (d, i) => i * (width / bufferLength))
        .attr('y', d => height - (d / 255) * height)
        .attr('width', (width / bufferLength) - 1)
        .attr('height', d => (d / 255) * height)
        .attr('fill', (d, i) => d3.interpolatePlasma(i / bufferLength))
        .attr('rx', 2);

      animationIdRef.current = requestAnimationFrame(renderFrame);
    };

    renderFrame();

    return () => {
      if (animationIdRef.current) cancelAnimationFrame(animationIdRef.current);
      audioContext.close();
    };
  }, [audioRef]);

  return (
    <div className="w-full flex justify-center items-center h-32 opacity-80">
      <svg ref={canvasRef} width="300" height="150" className="rounded-lg overflow-hidden" />
    </div>
  );
};

export default Visualizer;

import React, { useState, useEffect, useRef } from 'react';
import { Track } from '../types';
import { Play, Pause, SkipBack, SkipForward, Volume2, Repeat, Shuffle, Maximize2 } from 'lucide-react';

interface PlayerProps {
  currentTrack: Track;
  isPlaying: boolean;
  onPlayPause: () => void;
  onNext: () => void;
  onPrev: () => void;
  audioRef: React.RefObject<HTMLAudioElement>;
}

const Player: React.FC<PlayerProps> = ({ currentTrack, isPlaying, onPlayPause, onNext, onPrev, audioRef }) => {
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const updateProgress = () => {
      setProgress(audio.currentTime);
      setDuration(audio.duration || 0);
    };

    audio.addEventListener('timeupdate', updateProgress);
    audio.addEventListener('loadedmetadata', updateProgress);

    return () => {
      audio.removeEventListener('timeupdate', updateProgress);
      audio.removeEventListener('loadedmetadata', updateProgress);
    };
  }, [audioRef]);

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setProgress(time);
    }
  };

  const formatTime = (time: number) => {
    const mins = Math.floor(time / 60);
    const secs = Math.floor(time % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 glass border-t border-white/10 px-4 md:px-8 py-4 z-50">
      <div className="max-w-7xl mx-auto flex items-center justify-between gap-4">
        {/* Track Info */}
        <div className="flex items-center gap-4 w-1/3 min-w-0">
          <img src={currentTrack.coverUrl} className="w-14 h-14 rounded-md object-cover flex-shrink-0 shadow-lg" alt="Cover" />
          <div className="min-w-0">
            <h4 className="font-semibold text-sm md:text-base truncate text-white">{currentTrack.title}</h4>
            <p className="text-xs text-white/50 truncate">{currentTrack.artist}</p>
          </div>
        </div>

        {/* Controls */}
        <div className="flex flex-col items-center gap-2 w-1/3">
          <div className="flex items-center gap-6">
            <button className="text-white/40 hover:text-white transition-colors"><Shuffle size={18} /></button>
            <button onClick={onPrev} className="text-white hover:text-blue-400 transition-colors"><SkipBack size={24} /></button>
            <button 
              onClick={onPlayPause}
              className="w-10 h-10 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform"
            >
              {isPlaying ? <Pause size={24} /> : <Play size={24} className="ml-1" />}
            </button>
            <button onClick={onNext} className="text-white hover:text-blue-400 transition-colors"><SkipForward size={24} /></button>
            <button className="text-white/40 hover:text-white transition-colors"><Repeat size={18} /></button>
          </div>

          <div className="flex items-center gap-2 w-full max-w-md">
            <span className="text-[10px] text-white/40 tabular-nums">{formatTime(progress)}</span>
            <input 
              type="range"
              min="0"
              max={duration || 100}
              value={progress}
              onChange={handleSeek}
              className="flex-1 h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 transition-all"
            />
            <span className="text-[10px] text-white/40 tabular-nums">{formatTime(duration)}</span>
          </div>
        </div>

        {/* Volume & Extras */}
        <div className="flex items-center justify-end gap-4 w-1/3">
          <div className="hidden md:flex items-center gap-2">
            <Volume2 size={20} className="text-white/60" />
            <div className="w-24 h-1 bg-white/10 rounded-full">
              <div className="w-2/3 h-full bg-blue-500 rounded-full"></div>
            </div>
          </div>
          <button className="text-white/60 hover:text-white"><Maximize2 size={18} /></button>
        </div>
      </div>
    </div>
  );
};

export default Player;

import React, { useState } from 'react';
import { getMoodPlaylist, explainSong, generateLyrics } from '../services/geminiService';
import { Sparkles, Brain, Music, Wand2, Loader2, Play } from 'lucide-react';
import { Track, AIRecommendation } from '../types';

interface GeminiDJProps {
  currentTrack: Track;
}

const GeminiDJ: React.FC<GeminiDJProps> = ({ currentTrack }) => {
  const [mood, setMood] = useState('');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<AIRecommendation[]>([]);
  const [explanation, setExplanation] = useState('');
  const [lyrics, setLyrics] = useState('');
  const [activeTab, setActiveTab] = useState<'mood' | 'explain' | 'lyrics'>('mood');

  const handleMoodCuration = async () => {
    if (!mood) return;
    setLoading(true);
    const recs = await getMoodPlaylist(mood);
    setResults(recs);
    setLoading(false);
  };

  const handleExplain = async () => {
    setLoading(true);
    const text = await explainSong(currentTrack.title, currentTrack.artist);
    setExplanation(text);
    setLoading(false);
  };

  const handleLyrics = async () => {
    setLoading(true);
    const text = await generateLyrics(mood || "melancholic", "Synth-pop");
    setLyrics(text);
    setLoading(false);
  };

  return (
    <div className="glass rounded-2xl p-6 flex flex-col h-full overflow-hidden">
      <div className="flex items-center gap-2 mb-6">
        <div className="p-2 bg-blue-500/20 rounded-lg">
          <Sparkles className="text-blue-400" size={24} />
        </div>
        <h2 className="text-xl font-bold font-poppins">Gemini AI Studio</h2>
      </div>

      <div className="flex gap-2 mb-6 p-1 bg-white/5 rounded-xl">
        <button 
          onClick={() => setActiveTab('mood')}
          className={`flex-1 py-2 px-3 rounded-lg text-sm flex items-center justify-center gap-2 transition-all ${activeTab === 'mood' ? 'bg-blue-600 text-white shadow-lg' : 'text-white/60 hover:bg-white/5'}`}
        >
          <Music size={16} /> Mood DJ
        </button>
        <button 
          onClick={() => setActiveTab('explain')}
          className={`flex-1 py-2 px-3 rounded-lg text-sm flex items-center justify-center gap-2 transition-all ${activeTab === 'explain' ? 'bg-blue-600 text-white shadow-lg' : 'text-white/60 hover:bg-white/5'}`}
        >
          <Brain size={16} /> Explain
        </button>
        <button 
          onClick={() => setActiveTab('lyrics')}
          className={`flex-1 py-2 px-3 rounded-lg text-sm flex items-center justify-center gap-2 transition-all ${activeTab === 'lyrics' ? 'bg-blue-600 text-white shadow-lg' : 'text-white/60 hover:bg-white/5'}`}
        >
          <Wand2 size={16} /> Lyrics
        </button>
      </div>

      <div className="flex-1 overflow-y-auto pr-2 space-y-4">
        {activeTab === 'mood' && (
          <div className="space-y-4">
            <div className="relative">
              <input 
                value={mood}
                onChange={(e) => setMood(e.target.value)}
                placeholder="How are you feeling?"
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
              />
              <button 
                onClick={handleMoodCuration}
                disabled={loading || !mood}
                className="absolute right-2 top-1.5 p-1.5 bg-blue-500 rounded-lg hover:bg-blue-400 disabled:opacity-50 transition-colors"
              >
                {loading ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}
              </button>
            </div>

            {results.length > 0 && (
              <div className="space-y-3">
                {results.map((rec, i) => (
                  <div key={i} className="p-3 bg-white/5 border border-white/5 rounded-xl hover:bg-white/10 transition-colors group">
                    <div className="flex justify-between items-start mb-1">
                      <div>
                        <h4 className="font-semibold text-sm">{rec.title}</h4>
                        <p className="text-xs text-white/50">{rec.artist}</p>
                      </div>
                      <button className="opacity-0 group-hover:opacity-100 text-blue-400 transition-opacity">
                        <Play size={16} />
                      </button>
                    </div>
                    <p className="text-[11px] text-white/40 leading-relaxed italic">"{rec.reason}"</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {activeTab === 'explain' && (
          <div className="space-y-4">
            <div className="p-4 bg-white/5 rounded-xl border border-white/10">
              <h3 className="font-semibold text-blue-400 mb-1">{currentTrack.title}</h3>
              <p className="text-xs text-white/40 mb-3">by {currentTrack.artist}</p>
              <button 
                onClick={handleExplain}
                disabled={loading}
                className="w-full py-2 bg-blue-600 rounded-lg text-sm font-medium hover:bg-blue-500 flex items-center justify-center gap-2"
              >
                {loading ? <Loader2 className="animate-spin" size={16} /> : <Brain size={16} />} 
                Analyze this track
              </button>
            </div>
            {explanation && (
              <div className="text-sm text-white/70 leading-relaxed bg-blue-500/5 p-4 rounded-xl border border-blue-500/10 whitespace-pre-wrap">
                {explanation}
              </div>
            )}
          </div>
        )}

        {activeTab === 'lyrics' && (
          <div className="space-y-4">
             <div className="relative">
              <input 
                value={mood}
                onChange={(e) => setMood(e.target.value)}
                placeholder="Topic for your song..."
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
              />
              <button 
                onClick={handleLyrics}
                disabled={loading || !mood}
                className="absolute right-2 top-1.5 p-1.5 bg-blue-500 rounded-lg hover:bg-blue-400 disabled:opacity-50 transition-colors"
              >
                {loading ? <Loader2 className="animate-spin" size={18} /> : <Wand2 size={18} />}
              </button>
            </div>
            {lyrics && (
              <div className="text-xs text-white/60 font-mono leading-loose bg-purple-500/5 p-4 rounded-xl border border-purple-500/10 whitespace-pre-wrap">
                {lyrics}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default GeminiDJ;

import React, { useState, useRef, useEffect } from 'react';
import { MOCK_TRACKS } from './constants';
import { Track, ViewState } from './types';
import Sidebar from './components/Sidebar';
import Player from './components/Player';
import GeminiDJ from './components/GeminiDJ';
import Visualizer from './components/Visualizer';
import { Home, Search, Library, PlusCircle, Heart, Disc, Play, Clock, MoreHorizontal } from 'lucide-react';

const App: React.FC = () => {
  const [currentTrack, setCurrentTrack] = useState<Track>(MOCK_TRACKS[0]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.HOME);
  const audioRef = useRef<HTMLAudioElement>(null);

  const handlePlayPause = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const handleTrackSelect = (track: Track) => {
    setCurrentTrack(track);
    setIsPlaying(true);
    // Audio element auto-plays when source changes if specified or via ref
    if (audioRef.current) {
      audioRef.current.load();
      audioRef.current.play();
    }
  };

  const nextTrack = () => {
    const idx = MOCK_TRACKS.findIndex(t => t.id === currentTrack.id);
    const nextIdx = (idx + 1) % MOCK_TRACKS.length;
    handleTrackSelect(MOCK_TRACKS[nextIdx]);
  };

  const prevTrack = () => {
    const idx = MOCK_TRACKS.findIndex(t => t.id === currentTrack.id);
    const prevIdx = (idx - 1 + MOCK_TRACKS.length) % MOCK_TRACKS.length;
    handleTrackSelect(MOCK_TRACKS[prevIdx]);
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-[#0a0a0c] text-white overflow-hidden selection:bg-blue-500/30">
      <div className="flex-1 flex overflow-hidden">
        {/* Navigation Sidebar */}
        <aside className="w-64 glass border-r border-white/5 p-6 flex flex-col gap-8 hidden md:flex">
          <div className="flex items-center gap-3 px-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-500/20">
              <Disc className="text-white animate-spin-slow" size={20} />
            </div>
            <h1 className="text-xl font-bold tracking-tight font-poppins">NovaStream</h1>
          </div>

          <nav className="space-y-1">
            <NavItem icon={<Home size={20} />} label="Home" active={view === ViewState.HOME} onClick={() => setView(ViewState.HOME)} />
            <NavItem icon={<Search size={20} />} label="Search" active={false} />
            <NavItem icon={<Library size={20} />} label="Library" active={false} />
          </nav>

          <div className="space-y-4">
            <h3 className="text-[10px] font-bold text-white/30 uppercase tracking-widest px-2">Your Playlists</h3>
            <div className="space-y-1">
              <NavItem icon={<PlusCircle size={20} />} label="Create Playlist" active={false} />
              <NavItem icon={<Heart size={20} className="text-pink-500" />} label="Liked Songs" active={false} />
            </div>
          </div>

          <div className="mt-auto p-4 bg-gradient-to-br from-blue-600/20 to-purple-600/20 rounded-2xl border border-white/10">
            <p className="text-xs font-semibold mb-1">Nova Pro</p>
            <p className="text-[10px] text-white/50 mb-3">AI Curation & Lossless Audio</p>
            <button className="w-full py-2 bg-white text-black text-[10px] font-bold rounded-lg hover:scale-[1.02] transition-transform">UPGRADE</button>
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto bg-gradient-to-b from-white/5 to-transparent relative">
          <div className="p-6 md:p-10 max-w-6xl mx-auto space-y-10 pb-32">
            {/* Hero Section */}
            <div className="relative group">
              <div className="flex flex-col md:flex-row items-end gap-8 p-8 glass rounded-3xl overflow-hidden relative">
                <img 
                  src={currentTrack.coverUrl} 
                  className="w-48 h-48 md:w-64 md:h-64 rounded-2xl shadow-2xl object-cover hover:scale-[1.02] transition-transform duration-500" 
                  alt="Current Album" 
                />
                <div className="flex-1 space-y-4">
                  <span className="text-xs font-bold uppercase tracking-widest text-blue-400">Now Playing</span>
                  <h1 className="text-4xl md:text-6xl font-black font-poppins">{currentTrack.title}</h1>
                  <div className="flex items-center gap-2 text-white/60">
                    <span className="font-semibold text-white">{currentTrack.artist}</span>
                    <span>•</span>
                    <span className="text-sm">{currentTrack.album}</span>
                    <span>•</span>
                    <span className="text-sm">{currentTrack.genre}</span>
                  </div>
                  <div className="flex items-center gap-4 pt-4">
                    <button 
                      onClick={handlePlayPause}
                      className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-full font-bold shadow-xl shadow-blue-600/20 flex items-center gap-2 hover:scale-105 transition-all"
                    >
                      {isPlaying ? <Pause size={20} /> : <Play size={20} />} {isPlaying ? 'PAUSE' : 'PLAY'}
                    </button>
                    <button className="w-12 h-12 border border-white/20 rounded-full flex items-center justify-center hover:bg-white/10 transition-colors">
                      <Heart size={20} />
                    </button>
                    <button className="w-12 h-12 border border-white/20 rounded-full flex items-center justify-center hover:bg-white/10 transition-colors">
                      <MoreHorizontal size={20} />
                    </button>
                  </div>
                </div>

                {/* Embedded Visualizer */}
                <div className="absolute top-4 right-8 w-48 opacity-40">
                  <Visualizer isPlaying={isPlaying} audioRef={audioRef} />
                </div>
              </div>
            </div>

            {/* Trending Tracks */}
            <section className="space-y-6">
              <div className="flex justify-between items-end px-2">
                <h2 className="text-2xl font-bold font-poppins tracking-tight">Recent Discovery</h2>
                <button className="text-sm font-semibold text-white/40 hover:text-white transition-colors">Show All</button>
              </div>
              <div className="glass rounded-2xl overflow-hidden border border-white/5">
                <table className="w-full text-left">
                  <thead>
                    <tr className="text-[10px] font-bold text-white/30 uppercase border-b border-white/5">
                      <th className="py-4 px-6 w-12 text-center">#</th>
                      <th className="py-4 px-4">Title</th>
                      <th className="py-4 px-4 hidden md:table-cell">Album</th>
                      <th className="py-4 px-4 hidden sm:table-cell text-center"><Clock size={14} className="mx-auto" /></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-white/5">
                    {MOCK_TRACKS.map((track, i) => (
                      <tr 
                        key={track.id} 
                        onClick={() => handleTrackSelect(track)}
                        className={`group cursor-pointer transition-colors ${currentTrack.id === track.id ? 'bg-blue-500/10' : 'hover:bg-white/5'}`}
                      >
                        <td className="py-4 px-6 text-center text-sm font-medium text-white/40 group-hover:text-white">
                          {currentTrack.id === track.id && isPlaying ? (
                            <div className="flex items-center justify-center gap-0.5 h-3">
                              <div className="w-1 bg-blue-500 h-full animate-bounce" style={{animationDelay: '0s'}}></div>
                              <div className="w-1 bg-blue-500 h-2/3 animate-bounce" style={{animationDelay: '0.1s'}}></div>
                              <div className="w-1 bg-blue-500 h-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                            </div>
                          ) : i + 1}
                        </td>
                        <td className="py-4 px-4">
                          <div className="flex items-center gap-3">
                            <img src={track.coverUrl} className="w-10 h-10 rounded shadow" alt="cover" />
                            <div>
                              <p className={`text-sm font-semibold ${currentTrack.id === track.id ? 'text-blue-400' : 'text-white'}`}>{track.title}</p>
                              <p className="text-xs text-white/40">{track.artist}</p>
                            </div>
                          </div>
                        </td>
                        <td className="py-4 px-4 hidden md:table-cell text-sm text-white/40">{track.album}</td>
                        <td className="py-4 px-4 hidden sm:table-cell text-sm text-white/40 text-center tabular-nums">{track.duration}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </section>
          </div>
        </main>

        {/* Gemini AI Side Panel */}
        <aside className="w-96 glass border-l border-white/5 p-6 hidden lg:block">
          <GeminiDJ currentTrack={currentTrack} />
        </aside>
      </div>

      {/* Hidden Audio Element */}
      <audio 
        ref={audioRef} 
        src={currentTrack.audioUrl} 
        onEnded={nextTrack}
        crossOrigin="anonymous"
      />

      {/* Global Player Controls */}
      <Player 
        currentTrack={currentTrack} 
        isPlaying={isPlaying} 
        onPlayPause={handlePlayPause}
        onNext={nextTrack}
