                    <LogOut size={10} /> Đăng xuất
                  </button>
                </div>
              </div>
            )}
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto bg-gradient-to-b from-white/5 to-transparent relative">
          {/* Top Bar (Mobile/Tablets might need this more, but nice for Profile access) */}
          <div className="absolute top-0 right-0 p-6 z-10 md:hidden">
            <button 
              onClick={() => user ? null : setShowAuthModal(true)}
              className="w-10 h-10 bg-black/50 backdrop-blur rounded-full flex items-center justify-center border border-white/10"
            >
              {user ? (
                 <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-xs font-bold">
                  {user.name.charAt(0).toUpperCase()}
                </div>
              ) : (
                <UserIcon size={20} />
              )}
            </button>
          </div>

          <div className="p-6 md:p-10 max-w-6xl mx-auto space-y-10 pb-32 min-h-full">
            {renderMainContent()}
          </div>
        </main>

        {/* Gemini AI Side Panel */}
        <aside className="w-96 glass border-l border-white/5 p-6 hidden lg:block">
          <GeminiDJ currentTrack={currentTrack} />
        </aside>
      </div>

      {/* Hidden Audio Element */}
      <audio 
        ref={audioRef} 
        src={currentTrack.audioUrl} 
        onEnded={nextTrack}
        crossOrigin="anonymous"
      />

      {/* Global Player Controls */}
      <Player 
        currentTrack={currentTrack} 
        isPlaying={isPlaying} 
        onPlayPause={handlePlayPause}
        onNext={nextTrack}
        onPrev={prevTrack}
        audioRef={audioRef}
        onToggleLike={toggleLike}
        isLiked={likedTrackIds.has(currentTrack.id)}
      />
    </div>
  );
};

