  const [view, setView] = useState<ViewState>(ViewState.HOME);
  const [user, setUser] = useState<User | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [likedTrackIds, setLikedTrackIds] = useState<Set<string>>(new Set());
  const [userTracks, setUserTracks] = useState<Track[]>([]);

  const audioRef = useRef<HTMLAudioElement>(null);

  useEffect(() => {
    const initApp = async () => {
      await new Promise(resolve => setTimeout(resolve, 800));
      const storedUser = storage.getUser();
      const storedLiked = storage.getLikedTracks();
      if (storedUser) setUser(storedUser);
      if (storedLiked.length > 0) setLikedTrackIds(new Set(storedLiked));
      setIsAppLoading(false);
    };
    initApp();
  }, []);

  const handlePlayPause = () => {
    if (!audioRef.current) return;
    isPlaying ? audioRef.current.pause() : audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  const handleTrackSelect = (track: Track) => {
    setCurrentTrack(track);
    setIsPlaying(true);
    if (audioRef.current) {
      audioRef.current.load();
      audioRef.current.play();
    }
  };

  const nextTrack = () => {
    const all = [...MOCK_TRACKS, ...userTracks];
    const idx = all.findIndex(t => t.id === currentTrack.id);
    const nextIdx = (idx + 1) % all.length;
    handleTrackSelect(all[nextIdx]);
  };

  const prevTrack = () => {
    const all = [...MOCK_TRACKS, ...userTracks];
    const idx = all.findIndex(t => t.id === currentTrack.id);
    const prevIdx = (idx - 1 + all.length) % all.length;
    handleTrackSelect(all[prevIdx]);
  };

  const toggleLike = (trackId: string) => {
    setLikedTrackIds(prev => {
      const next = new Set(prev);
      next.has(trackId) ? next.delete(trackId) : next.add(trackId);
      storage.saveLikedTracks(Array.from(next));
      return next;
    });
  };

  const handleDownload = (track: Track) => {
    // Simulate downloading by creating a link
    const link = document.createElement('a');
    link.href = track.audioUrl;
    link.download = `${track.artist} - ${track.title}.mp3`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const newTrack: Track = {
        id: `local-${Date.now()}`,
        title: file.name.replace(/\.[^/.]+$/, ""),
        artist: user?.name || 'Local User',
        album: 'Bản tải lên',
        duration: '??:??',
        coverUrl: 'https://images.unsplash.com/photo-1511671782779-c97d3d27a1d4?w=400&h=400&fit=crop',
        audioUrl: URL.createObjectURL(file),
        genre: 'Tải lên',
        isLocal: true
      };
      setUserTracks([newTrack, ...userTracks]);
      setView(ViewState.LIBRARY);
    }
  };

  const getLikedTracks = () => [...MOCK_TRACKS, ...userTracks].filter(t => likedTrackIds.has(t.id));

  const renderMainContent = () => {
    switch (view) {
      case ViewState.SEARCH:
        return (
          <SearchView 
            allTracks={[...MOCK_TRACKS, ...userTracks]}
            currentTrack={currentTrack}
            isPlaying={isPlaying}
            onTrackSelect={handleTrackSelect}
            onToggleLike={toggleLike}
            onDownload={handleDownload}
            likedTrackIds={likedTrackIds}
          />
        );
      case ViewState.LIBRARY:
        return (
          <LibraryView 
            user={user}
            // Fixed truthiness error by using a block statement for side effects
            onOpenAuth={() => { setAuthView('login'); setShowAuthModal(true); }}
            likedTracks={getLikedTracks()}
            currentTrack={currentTrack}
            isPlaying={isPlaying}
            onTrackSelect={handleTrackSelect}
            onToggleLike={toggleLike}
            onDownload={handleDownload}
            likedTrackIds={likedTrackIds}
          />
        );
      case ViewState.UPLOAD:
        return (
          <div className="animate-fade-in space-y-8">
            <div className="p-12 border-2 border-dashed border-white/10 rounded-3xl flex flex-col items-center justify-center text-center space-y-6 bg-white/5">
              <div className="w-20 h-20 bg-blue-600/20 rounded-full flex items-center justify-center text-blue-500">
                <CloudUpload size={40} />
              </div>
              <div>
                <h2 className="text-2xl font-bold">Tải lên âm nhạc của bạn</h2>
                <p className="text-white/40 max-w-sm mt-2">Chia sẻ những giai điệu yêu thích từ máy tính của bạn vào thư viện SoundTrack.</p>
              </div>
              <label className="bg-blue-600 hover:bg-blue-500 px-8 py-3 rounded-full font-bold cursor-pointer transition-transform hover:scale-105">
                Chọn tệp MP3
                <input type="file" accept="audio/mp3" className="hidden" onChange={handleFileUpload} />
              </label>
            </div>
            {userTracks.length > 0 && (
              <div className="space-y-4">
                <h3 className="text-xl font-bold">Vừa tải lên</h3>
                <TrackList 
                  tracks={userTracks}
                  currentTrack={currentTrack}
                  isPlaying={isPlaying}
                  onTrackSelect={handleTrackSelect}
                  onToggleLike={toggleLike}
                  onDownload={handleDownload}
                  likedTrackIds={likedTrackIds}
                />
              </div>
            )}
          </div>
        );
      case ViewState.HOME:
      default:
        return (
          <div className="space-y-12">
            {/* Featured Section */}
            <section>
              <h2 className="text-2xl font-black font-poppins mb-6 flex items-center gap-2">
                <Music className="text-blue-500" /> Bài hát nổi bật
              </h2>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {MOCK_TRACKS.slice(0, 3).map(track => (
                  <div 
                    key={track.id} 
                    onClick={() => handleTrackSelect(track)}
                    className="group relative h-48 rounded-2xl overflow-hidden cursor-pointer shadow-xl border border-white/5 transition-all hover:border-blue-500/50"
                  >
                    <img src={track.coverUrl} className="absolute inset-0 w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" alt={track.title} />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent p-6 flex flex-col justify-end">
                      <span className="text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1">{track.genre}</span>
                      <h3 className="text-xl font-bold text-white truncate">{track.title}</h3>
                      <p className="text-sm text-white/60 truncate">{track.artist}</p>
                    </div>
                    <div className="absolute top-4 right-4 w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center shadow-lg opacity-0 translate-y-2 group-hover:opacity-100 group-hover:translate-y-0 transition-all">
                      <Play size={20} fill="white" className="ml-1" />
                    </div>
                  </div>
                ))}
              </div>
            </section>

            {/* Hero Banner for Vietnamese Music */}
            <div className="relative group p-8 rounded-3xl overflow-hidden glass border border-blue-500/20">
              <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full blur-[100px] pointer-events-none"></div>
              <div className="relative z-10 flex flex-col md:flex-row items-center gap-8">
                <img src={currentTrack.coverUrl} className="w-48 h-48 md:w-56 md:h-56 rounded-2xl shadow-2xl object-cover" alt="Banner" />
                <div className="flex-1 space-y-4">
                  <div className="flex items-center gap-2">
                    <span className="px-2 py-0.5 bg-red-600/80 text-[10px] font-bold rounded uppercase">V-Pop Priority</span>
                    <span className="text-xs font-bold uppercase tracking-widest text-blue-400">Gợi ý hôm nay</span>
                  </div>
                  <h1 className="text-4xl md:text-5xl font-black font-poppins">{currentTrack.title}</h1>
                  <p className="text-white/60 italic leading-relaxed max-w-lg">{currentTrack.description || 'Khám phá những giai điệu mới nhất từ các nghệ sĩ Việt Nam.'}</p>
                  <div className="flex items-center gap-4 pt-4">
                    <button onClick={handlePlayPause} className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-full font-bold shadow-xl flex items-center gap-2 transition-all">
                      {isPlaying ? <Pause size={20} /> : <Play size={20} />} {isPlaying ? 'Tạm dừng' : 'Phát ngay'}
                    </button>
                    <button onClick={() => toggleLike(currentTrack.id)} className={`w-12 h-12 border border-white/20 rounded-full flex items-center justify-center hover:bg-white/10 transition-colors ${likedTrackIds.has(currentTrack.id) ? 'text-pink-500' : ''}`}>
                      <Heart size={20} fill={likedTrackIds.has(currentTrack.id) ? "currentColor" : "none"} />
                    </button>
                  </div>
                </div>
              </div>
            </div>

            {/* All Tracks List */}
            <section className="space-y-6">
              <div className="flex justify-between items-end px-2">
                <h2 className="text-2xl font-bold font-poppins">Bảng xếp hạng</h2>
              </div>
              <TrackList 
                tracks={MOCK_TRACKS}
                currentTrack={currentTrack}
                isPlaying={isPlaying}
                onTrackSelect={handleTrackSelect}
                onToggleLike={toggleLike}
                onDownload={handleDownload}
                likedTrackIds={likedTrackIds}
              />
            </section>
          </div>
        );
    }
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-[#0a0a0c] text-white overflow-hidden selection:bg-blue-500/30">
      <AuthModal isOpen={showAuthModal} onClose={() => setShowAuthModal(false)} onLogin={(u) => {setUser(u); storage.saveUser(u)}} initialView={authView} />
      <div className="flex-1 flex overflow-hidden">
        <aside className="w-64 glass border-r border-white/5 p-6 flex flex-col gap-8 hidden md:flex">
