            <NavItem icon={<Library size={20} />} label="Thư viện" active={view === ViewState.LIBRARY} onClick={() => setView(ViewState.LIBRARY)} />
            <NavItem icon={<Upload size={20} />} label="Tải lên" active={view === ViewState.UPLOAD} onClick={() => setView(ViewState.UPLOAD)} />
          </nav>
          <div className="space-y-4">
            <h3 className="text-[10px] font-bold text-white/30 uppercase tracking-widest px-2">Hoạt động</h3>
            <div className="space-y-1">
              <NavItem icon={<Heart size={20} className="text-pink-500" />} label="Yêu thích" active={false} onClick={() => setView(ViewState.LIBRARY)} />
            </div>
          </div>
          <div className="mt-auto">
            {!user ? (
               <div className="p-4 bg-gradient-to-br from-blue-600/20 to-purple-600/20 rounded-2xl border border-white/10 text-center">
                <p className="text-xs font-semibold">Gói Pro</p>
                <button onClick={() => setShowAuthModal(true)} className="w-full mt-3 py-2 bg-white text-black text-[10px] font-bold rounded-lg">ĐĂNG NHẬP</button>
              </div>
            ) : (
              <div className="p-4 bg-white/5 rounded-2xl border border-white/5 flex items-center gap-3">
                <img src={user.avatar} alt={user.name} className="w-8 h-8 rounded-full" />
