                  <p className="text-sm font-semibold truncate">{user.name}</p>
                  <button onClick={() => {setUser(null); storage.clearUser(); setView(ViewState.HOME)}} className="text-[10px] text-white/50 hover:text-white flex items-center gap-1"><LogOut size={10} /> Thoát</button>
                </div>
