import React, { useEffect, useRef, useState } from 'react';
import { Track } from '../types';
import { Music, Sparkles, MessageSquareQuote } from 'lucide-react';

interface LyricsViewProps {
  track: Track;
  currentTime: number;
  onSeek: (time: number) => void;
}

const LyricsView: React.FC<LyricsViewProps> = ({ track, currentTime, onSeek }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState(-1);

  useEffect(() => {
    if (!track.lyrics) return;

    const index = track.lyrics.findLastIndex(line => currentTime >= line.time);
    if (index !== activeIndex) {
      setActiveIndex(index);

      // Auto-scroll logic
      const activeElement = containerRef.current?.children[index] as HTMLElement;
      if (activeElement) {
        activeElement.scrollIntoView({
          behavior: 'smooth',
          block: 'center'
        });
      }
    }
  }, [currentTime, track.lyrics, activeIndex]);

  if (!track.lyrics || track.lyrics.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-center space-y-6 animate-fade-in p-8">
        <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center animate-pulse">
          <Music size={40} className="text-white/20" />
        </div>
        <div>
          <h2 className="text-3xl font-black font-poppins mb-2">Lời bài hát đang được cập nhật</h2>
          <p className="text-white/40">Giai điệu này thật tuyệt vời đúng không? Hãy tận hưởng âm nhạc nhé.</p>
        </div>
        <button className="flex items-center gap-2 px-6 py-3 bg-blue-600 rounded-full font-bold hover:bg-blue-500 transition-all">
          <Sparkles size={18} /> Nhờ AI tìm lời giúp
        </button>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col relative overflow-hidden">
      {/* Background blurred cover */}
      <div 
        className="absolute inset-0 opacity-20 blur-[120px] pointer-events-none scale-150 transition-all duration-1000"
        style={{ backgroundImage: `url(${track.coverUrl})`, backgroundSize: 'cover' }}
      ></div>

      <div className="relative z-10 flex flex-col md:flex-row h-full gap-12 p-4 md:p-12 items-center md:items-start overflow-hidden">
        {/* Left Side: Track Info */}
        <div className="w-full md:w-1/3 flex flex-col items-center md:items-start space-y-6 mt-12 md:sticky md:top-12">
          <div className="relative group">
            <img 
              src={track.coverUrl} 
              alt={track.title} 
              className="w-48 h-48 md:w-64 md:h-64 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] object-cover transition-transform duration-500 group-hover:scale-105"
            />
            <div className="absolute inset-0 bg-blue-600/20 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity"></div>
          </div>
          <div className="text-center md:text-left">
            <h1 className="text-4xl font-black font-poppins mb-2 tracking-tight">{track.title}</h1>
            <p className="text-xl text-white/60 font-medium">{track.artist}</p>
          </div>

          <div className="hidden md:block p-4 bg-white/5 border border-white/10 rounded-2xl max-w-xs">
            <div className="flex items-center gap-2 text-blue-400 text-xs font-bold uppercase tracking-widest mb-2">
              <MessageSquareQuote size={14} /> AI Chú thích
            </div>
            <p className="text-xs text-white/40 leading-relaxed italic">
              "Giai điệu này mang đậm chất liệu dân gian Việt Nam phối hợp với âm hưởng Pop hiện đại."
            </p>
          </div>
        </div>

        {/* Right Side: Scrolling Lyrics */}
        <div 
          ref={containerRef}
          className="flex-1 w-full overflow-y-auto space-y-10 py-[30vh] custom-scrollbar px-4"
          style={{ scrollBehavior: 'smooth' }}
        >
          {track.lyrics.map((line, i) => {
            const isActive = i === activeIndex;
            const isPassed = i < activeIndex;

            return (
              <div 
                key={i}
                onClick={() => onSeek(line.time)}
                className={`cursor-pointer transition-all duration-500 transform ${
                  isActive 
                    ? 'text-white text-3xl md:text-5xl font-black scale-100 opacity-100 translate-x-2' 
                    : isPassed 
                      ? 'text-white/20 text-xl md:text-3xl font-bold opacity-40 hover:opacity-60' 
                      : 'text-white/40 text-xl md:text-3xl font-bold opacity-60 hover:opacity-100'
                }`}
              >
                {line.text}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default LyricsView;

import React, { useState, useEffect } from 'react';
import { Track } from '../types';
import { Play, Pause, SkipBack, SkipForward, Volume2, Repeat, Shuffle, Maximize2, Heart, Mic2 } from 'lucide-react';

interface PlayerProps {
  currentTrack: Track;
  isPlaying: boolean;
  onPlayPause: () => void;
  onNext: () => void;
  onPrev: () => void;
  onOpenLyrics?: () => void;
  audioRef: React.RefObject<HTMLAudioElement>;
  onToggleLike: (trackId: string) => void;
  isLiked: boolean;
}

const Player: React.FC<PlayerProps> = ({ 
  currentTrack, 
  isPlaying, 
  onPlayPause, 
  onNext, 
  onPrev, 
  onOpenLyrics,
  audioRef,
  onToggleLike,
  isLiked
}) => {
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const updateProgress = () => {
      setProgress(audio.currentTime);
      setDuration(audio.duration || 0);
    };

    audio.addEventListener('timeupdate', updateProgress);
    audio.addEventListener('loadedmetadata', updateProgress);

    return () => {
      audio.removeEventListener('timeupdate', updateProgress);
      audio.removeEventListener('loadedmetadata', updateProgress);
    };
  }, [audioRef]);

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setProgress(time);
    }
  };

  const formatTime = (time: number) => {
    const mins = Math.floor(time / 60);
    const secs = Math.floor(time % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 glass border-t border-white/10 px-4 md:px-8 py-4 z-50 transition-all duration-500 hover:bg-[#0a0a0c]/80">
      <div className="max-w-7xl mx-auto flex items-center justify-between gap-4">
        {/* Track Info */}
        <div className="flex items-center gap-4 w-1/3 min-w-0">
          <div 
            onClick={onOpenLyrics}
            className="group relative cursor-pointer"
          >
            <img src={currentTrack.coverUrl} className="w-14 h-14 rounded-md object-cover flex-shrink-0 shadow-lg transition-transform group-hover:scale-110" alt="Cover" />
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center rounded-md transition-opacity">
               <Maximize2 size={16} />
            </div>
          </div>
          <div className="min-w-0 flex-1">
            <h4 className="font-semibold text-sm md:text-base truncate text-white hover:text-blue-400 cursor-pointer" onClick={onOpenLyrics}>{currentTrack.title}</h4>
            <p className="text-xs text-white/50 truncate hover:text-white transition-colors cursor-pointer">{currentTrack.artist}</p>
          </div>
          <button 
            onClick={() => onToggleLike(currentTrack.id)}
            className={`hidden sm:block transition-colors ${isLiked ? 'text-pink-500' : 'text-white/20 hover:text-white'}`}
          >
            <Heart size={18} fill={isLiked ? "currentColor" : "none"} />
          </button>
        </div>

        {/* Controls */}
        <div className="flex flex-col items-center gap-2 w-1/3">
          <div className="flex items-center gap-4 md:gap-8">
            <button className="hidden md:block text-white/40 hover:text-white transition-colors"><Shuffle size={18} /></button>
            <button onClick={onPrev} className="text-white hover:text-blue-400 transition-colors"><SkipBack size={24} /></button>
            <button 
              onClick={onPlayPause}
              className="w-10 h-10 md:w-12 md:h-12 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform shadow-[0_0_20px_rgba(255,255,255,0.2)]"
            >
              {isPlaying ? <Pause size={24} /> : <Play size={24} className="ml-1" />}
            </button>
            <button onClick={onNext} className="text-white hover:text-blue-400 transition-colors"><SkipForward size={24} /></button>
            <button className="hidden md:block text-white/40 hover:text-white transition-colors"><Repeat size={18} /></button>
          </div>

          <div className="flex items-center gap-3 w-full max-w-md">
            <span className="text-[10px] text-white/30 tabular-nums w-8 text-right">{formatTime(progress)}</span>
            <div className="relative flex-1 group py-2">
              <input 
                type="range"
                min="0"
                max={duration || 100}
                value={progress}
                onChange={handleSeek}
                className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 transition-all"
              />
              <div 
                className="absolute top-1/2 left-0 h-1 bg-blue-500 rounded-lg pointer-events-none -translate-y-1/2" 
                style={{ width: `${(progress / (duration || 1)) * 100}%` }}
              ></div>
            </div>
            <span className="text-[10px] text-white/30 tabular-nums w-8">{formatTime(duration)}</span>
          </div>
        </div>

        {/* Extras */}
        <div className="flex items-center justify-end gap-3 md:gap-5 w-1/3">
          <button 
            onClick={onOpenLyrics}
            className="p-2 hover:bg-white/5 rounded-full transition-colors text-white/60 hover:text-blue-400"
            title="Lời bài hát"
          >
            <Mic2 size={20} />
          </button>
          <div className="hidden lg:flex items-center gap-2 group">
            <Volume2 size={20} className="text-white/60 group-hover:text-white" />
            <div className="w-20 h-1 bg-white/10 rounded-full overflow-hidden">
              <div className="w-2/3 h-full bg-blue-500 rounded-full"></div>
            </div>
          </div>
          <button className="hidden sm:block text-white/60 hover:text-white"><Maximize2 size={18} /></button>
        </div>
      </div>
