  );
};

export default Player;

import React, { useState, useRef, useEffect } from 'react';
import { MOCK_TRACKS, RECOMMENDED_PLAYLISTS } from './constants';
import { Track, ViewState, User, Playlist } from './types';
import Player from './components/Player';
import GeminiDJ from './components/GeminiDJ';
import Visualizer from './components/Visualizer';
import AuthModal from './components/AuthModal';
import SearchView from './components/SearchView';
import LibraryView from './components/LibraryView';
import TrackList from './components/TrackList';
import PlaylistCard from './components/PlaylistCard';
import PlaylistView from './components/PlaylistView';
import LyricsView from './components/LyricsView';
import { storage } from './services/storage';
import { Home, Search, Library, PlusCircle, Heart, Disc, Play, Pause, MoreHorizontal, User as UserIcon, LogOut, Loader2, ChevronLeft, ChevronRight, Upload, Music, CloudUpload, X, ListMusic, Mic2 } from 'lucide-react';

const App: React.FC = () => {
  const [isAppLoading, setIsAppLoading] = useState(true);
  const [currentTrack, setCurrentTrack] = useState<Track>(MOCK_TRACKS[0]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.HOME);
  const [user, setUser] = useState<User | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [likedTrackIds, setLikedTrackIds] = useState<Set<string>>(new Set());
  const [userTracks, setUserTracks] = useState<Track[]>([]);
  const [userPlaylists, setUserPlaylists] = useState<Playlist[]>([]);
  const [selectedPlaylist, setSelectedPlaylist] = useState<Playlist | null>(null);
  const [currentTime, setCurrentTime] = useState(0);

  const audioRef = useRef<HTMLAudioElement>(null);

  useEffect(() => {
    const initApp = async () => {
      await new Promise(resolve => setTimeout(resolve, 800));
      const storedUser = storage.getUser();
      const storedLiked = storage.getLikedTracks();
      const storedPlaylists = storage.getUserPlaylists();

      if (storedUser) setUser(storedUser);
      if (storedLiked.length > 0) setLikedTrackIds(new Set(storedLiked));
      if (storedPlaylists.length > 0) setUserPlaylists(storedPlaylists);

      setIsAppLoading(false);
    };
    initApp();
  }, []);

  // Update current time state for lyrics sync
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const handleTimeUpdate = () => {
      setCurrentTime(audio.currentTime);
    };

    audio.addEventListener('timeupdate', handleTimeUpdate);
    return () => audio.removeEventListener('timeupdate', handleTimeUpdate);
  }, []);

  // Centralized Playback Management
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    if (isPlaying) {
      const playPromise = audio.play();
      if (playPromise !== undefined) {
        playPromise.catch(error => {
          if (error.name === 'AbortError' || error.name === 'NotAllowedError') {
            console.log("Playback interrupted or deferred");
          } else {
            console.error("Playback failed: ", error);
          }
          if (error.name === 'NotAllowedError') setIsPlaying(false);
        });
      }
    } else {
      audio.pause();
    }
  }, [isPlaying, currentTrack]);

  const handlePlayPause = () => {
    setIsPlaying(prev => !prev);
  };

  const handleTrackSelect = (track: Track) => {
    if (currentTrack.id === track.id) {
      handlePlayPause();
      return;
    }
    setCurrentTrack(track);
    setIsPlaying(true);
  };

  const nextTrack = () => {
    const all = [...MOCK_TRACKS, ...userTracks];
    const idx = all.findIndex(t => t.id === currentTrack.id);
    const nextIdx = (idx + 1) % all.length;
    handleTrackSelect(all[nextIdx]);
  };

  const prevTrack = () => {
    const all = [...MOCK_TRACKS, ...userTracks];
    const idx = all.findIndex(t => t.id === currentTrack.id);
    const prevIdx = (idx - 1 + all.length) % all.length;
    handleTrackSelect(all[prevIdx]);
  };

  const toggleLike = (trackId: string) => {
    setLikedTrackIds(prev => {
      const next = new Set(prev);
      next.has(trackId) ? next.delete(trackId) : next.add(trackId);
      storage.saveLikedTracks(Array.from(next));
      return next;
    });
  };

  const handleDownload = (track: Track) => {
    const link = document.createElement('a');
    link.href = track.audioUrl;
    link.download = `${track.artist} - ${track.title}.mp3`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleCreatePlaylist = () => {
    if (!user) {
      setAuthView('login');
      setShowAuthModal(true);
      return;
    }
    const newPlaylist: Playlist = {
      id: `pl-${Date.now()}`,
      name: `Danh sách mới #${userPlaylists.length + 1}`,
      description: 'Mô tả playlist của bạn',
      tracks: [],
      coverUrl: 'https://images.unsplash.com/photo-1493225255756-d9584f8606e9?w=400&h=400&fit=crop',
      createdBy: user.id
    };
    const updated = [newPlaylist, ...userPlaylists];
    setUserPlaylists(updated);
    storage.saveUserPlaylists(updated);
    handleOpenPlaylist(newPlaylist);
  };

  const handleOpenPlaylist = (playlist: Playlist) => {
    setSelectedPlaylist(playlist);
    setView(ViewState.PLAYLIST_DETAIL);
  };

  const handleSeek = (time: number) => {
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const newTrack: Track = {
        id: `local-${Date.now()}`,
        title: file.name.replace(/\.[^/.]+$/, ""),
        artist: user?.name || 'Local User',
        album: 'Bản tải lên',
        duration: '??:??',
        coverUrl: 'https://images.unsplash.com/photo-1511671782779-c97d3d27a1d4?w=400&h=400&fit=crop',
        audioUrl: URL.createObjectURL(file),
        genre: 'Tải lên',
        isLocal: true
      };
      setUserTracks([newTrack, ...userTracks]);
      setView(ViewState.LIBRARY);
    }
  };

  const getLikedTracks = () => [...MOCK_TRACKS, ...userTracks].filter(t => likedTrackIds.has(t.id));

  const renderMainContent = () => {
    switch (view) {
      case ViewState.SEARCH:
        return (
          <SearchView 
            allTracks={[...MOCK_TRACKS, ...userTracks]}
            currentTrack={currentTrack}
            isPlaying={isPlaying}
            onTrackSelect={handleTrackSelect}
            onToggleLike={toggleLike}
            onDownload={handleDownload}
            likedTrackIds={likedTrackIds}
          />
        );
      case ViewState.LIBRARY:
        return (
          <LibraryView 
            user={user}
            onOpenAuth={() => { setAuthView('login'); setShowAuthModal(true); }}
            likedTracks={getLikedTracks()}
            currentTrack={currentTrack}
            isPlaying={isPlaying}
            onTrackSelect={handleTrackSelect}
            onToggleLike={toggleLike}
            onDownload={handleDownload}
            likedTrackIds={likedTrackIds}
          />
        );
      case ViewState.LYRICS:
        return (
          <LyricsView 
            track={currentTrack} 
            currentTime={currentTime}
            onSeek={handleSeek}
          />
        );
      case ViewState.PLAYLIST_DETAIL:
        return selectedPlaylist ? (
          <PlaylistView 
            playlist={selectedPlaylist}
            currentTrack={currentTrack}
            isPlaying={isPlaying}
            onTrackSelect={handleTrackSelect}
            onToggleLike={toggleLike}
            onDownload={handleDownload}
            likedTrackIds={likedTrackIds}
          />
        ) : null;
      case ViewState.UPLOAD:
        return (
          <div className="animate-fade-in space-y-8">
            <div className="p-12 border-2 border-dashed border-white/10 rounded-3xl flex flex-col items-center justify-center text-center space-y-6 bg-white/5">
              <div className="w-20 h-20 bg-blue-600/20 rounded-full flex items-center justify-center text-blue-500">
                <CloudUpload size={40} />
              </div>
              <div>
                <h2 className="text-2xl font-bold">Tải lên âm nhạc của bạn</h2>
                <p className="text-white/40 max-w-sm mt-2">Chia sẻ những giai điệu yêu thích từ máy tính của bạn vào thư viện SoundTrack.</p>
              </div>
              <label className="bg-blue-600 hover:bg-blue-500 px-8 py-3 rounded-full font-bold cursor-pointer transition-transform hover:scale-105">
                Chọn tệp MP3
                <input type="file" accept="audio/mp3" className="hidden" onChange={handleFileUpload} />
              </label>
            </div>
          </div>
        );
      case ViewState.HOME:
      default:
        return (
          <div className="space-y-12">
            {/* Featured Tracks */}
            <section>
              <h2 className="text-2xl font-black font-poppins mb-6 flex items-center gap-2">
                <Music className="text-blue-500" /> Bài hát nổi bật
              </h2>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {MOCK_TRACKS.slice(0, 3).map(track => (
                  <div 
                    key={track.id} 
                    onClick={() => handleTrackSelect(track)}
                    className="group relative h-48 rounded-2xl overflow-hidden cursor-pointer shadow-xl border border-white/5 transition-all hover:border-blue-500/50"
                  >
                    <img src={track.coverUrl} className="absolute inset-0 w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" alt={track.title} />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent p-6 flex flex-col justify-end">
                      <span className="text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1">{track.genre}</span>
                      <h3 className="text-xl font-bold text-white truncate">{track.title}</h3>
                      <p className="text-sm text-white/60 truncate">{track.artist}</p>
                    </div>
                  </div>
                ))}
              </div>
            </section>

            {/* Recommended Playlists */}
            <section>
              <div className="flex justify-between items-end mb-6 px-2">
                <div>
                  <h2 className="text-2xl font-black font-poppins">Dành cho bạn</h2>
                  <p className="text-sm text-white/40">Gợi ý dựa trên sở thích âm nhạc của bạn</p>
                </div>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-6">
                {RECOMMENDED_PLAYLISTS.map(playlist => (
                  <PlaylistCard key={playlist.id} playlist={playlist} onClick={handleOpenPlaylist} />
                ))}
              </div>
            </section>

            {/* Banner V-Pop */}
            <div 
              className="relative group p-8 rounded-3xl overflow-hidden glass border border-blue-500/20 cursor-pointer"
              onClick={() => setView(ViewState.LYRICS)}
            >
              <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full blur-[100px] pointer-events-none"></div>
              <div className="relative z-10 flex flex-col md:flex-row items-center gap-8">
                <div className="relative">
                  <img src={currentTrack.coverUrl} className="w-48 h-48 md:w-56 md:h-56 rounded-2xl shadow-2xl object-cover" alt="Banner" />
                  {isPlaying && (
                    <div className="absolute -bottom-4 -right-4 w-12 h-12 bg-blue-600 rounded-full flex items-center justify-center animate-bounce">
                       <Mic2 size={24} />
                    </div>
                  )}
                </div>
                <div className="flex-1 space-y-4">
                  <div className="flex items-center gap-2">
                    <span className="px-2 py-0.5 bg-red-600/80 text-[10px] font-bold rounded uppercase">V-Pop Priority</span>
                    <span className="text-xs font-bold uppercase tracking-widest text-blue-400">Đang phát lôi cuốn</span>
                  </div>
                  <h1 className="text-4xl md:text-5xl font-black font-poppins">{currentTrack.title}</h1>
                  <p className="text-white/60 italic leading-relaxed max-w-lg">Nhấn vào đây để xem lời bài hát đang chạy theo giai điệu.</p>
                  <div className="flex items-center gap-4 pt-4">
                    <button onClick={(e) => { e.stopPropagation(); handlePlayPause(); }} className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-full font-bold shadow-xl flex items-center gap-2 transition-all">
                      {isPlaying ? <Pause size={20} /> : <Play size={20} />} {isPlaying ? 'Tạm dừng' : 'Phát ngay'}
                    </button>
                    <button onClick={(e) => { e.stopPropagation(); toggleLike(currentTrack.id); }} className={`w-12 h-12 border border-white/20 rounded-full flex items-center justify-center hover:bg-white/10 transition-colors ${likedTrackIds.has(currentTrack.id) ? 'text-pink-500' : ''}`}>
                      <Heart size={20} fill={likedTrackIds.has(currentTrack.id) ? "currentColor" : "none"} />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-[#0a0a0c] text-white overflow-hidden selection:bg-blue-500/30">
      <AuthModal isOpen={showAuthModal} onClose={() => setShowAuthModal(false)} onLogin={(u) => {setUser(u); storage.saveUser(u)}} initialView={authView} />

      <div className="flex-1 flex overflow-hidden">
        {/* Sidebar hides when in Lyrics view for full immersion */}
        <aside className={`${view === ViewState.LYRICS ? 'w-0 opacity-0 pointer-events-none' : 'w-64 opacity-100'} transition-all duration-500 glass border-r border-white/5 p-6 flex flex-col gap-8 hidden md:flex overflow-hidden`}>
          <div className="flex items-center gap-3 px-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg"><Disc className="animate-spin-slow text-white" size={20} /></div>
            <h1 className="text-xl font-bold font-poppins">SoundTrack</h1>
          </div>
          <nav className="space-y-1">
            <NavItem icon={<Home size={20} />} label="Trang chủ" active={view === ViewState.HOME} onClick={() => setView(ViewState.HOME)} />
            <NavItem icon={<Search size={20} />} label="Tìm kiếm" active={view === ViewState.SEARCH} onClick={() => setView(ViewState.SEARCH)} />
            <NavItem icon={<Library size={20} />} label="Thư viện" active={view === ViewState.LIBRARY} onClick={() => setView(ViewState.LIBRARY)} />
            <NavItem icon={<Upload size={20} />} label="Tải lên" active={view === ViewState.UPLOAD} onClick={() => setView(ViewState.UPLOAD)} />
          </nav>

          <div className="space-y-4 flex-1 overflow-y-auto pr-2 custom-scrollbar">
            <h3 className="text-[10px] font-bold text-white/30 uppercase tracking-widest px-2">Playlist</h3>
            <div className="space-y-1">
              <NavItem icon={<PlusCircle size={20} />} label="Tạo mới" active={false} onClick={handleCreatePlaylist} />
              <NavItem icon={<Heart size={20} className="text-pink-500" />} label="Yêu thích" active={false} onClick={() => setView(ViewState.LIBRARY)} />
              {userPlaylists.map(pl => (
                <button 
                  key={pl.id}
                  onClick={() => handleOpenPlaylist(pl)}
                  className={`w-full flex items-center gap-3 px-4 py-2 rounded-xl text-sm transition-all text-left truncate ${selectedPlaylist?.id === pl.id && view === ViewState.PLAYLIST_DETAIL ? 'bg-white/10 text-white' : 'text-white/40 hover:text-white hover:bg-white/5'}`}
                >
                  <ListMusic size={18} />
                  <span className="truncate">{pl.name}</span>
                </button>
              ))}
            </div>
          </div>
        </aside>

        <main className="flex-1 overflow-y-auto bg-gradient-to-b from-white/5 to-transparent relative">
          {/* Header hides in Lyrics view */}
          <header className={`${view === ViewState.LYRICS ? 'opacity-0 -translate-y-full' : 'opacity-100 translate-y-0'} transition-all duration-500 sticky top-0 z-20 flex items-center justify-between px-6 py-4 bg-[#0a0a0c]/90 backdrop-blur-md`}>
            <div className="flex gap-2">
              <button onClick={() => setView(ViewState.HOME)} className="w-8 h-8 rounded-full bg-black/50 flex items-center justify-center text-white/60 hover:text-white transition-colors"><ChevronLeft size={20} /></button>
              <button className="w-8 h-8 rounded-full bg-black/50 flex items-center justify-center text-white/60 cursor-not-allowed"><ChevronRight size={20} /></button>
            </div>
            <div className="flex items-center gap-4">
              {!user ? (
                <>
                  <button onClick={() => { setAuthView('register'); setShowAuthModal(true); }} className="text-white/60 hover:text-white font-semibold text-xs tracking-widest uppercase">Đăng ký</button>
                  <button onClick={() => { setAuthView('login'); setShowAuthModal(true); }} className="bg-white text-black px-8 py-2.5 rounded-full font-bold text-sm">Đăng nhập</button>
                </>
              ) : (
                <div className="flex items-center gap-3 bg-white/5 px-3 py-1.5 rounded-full border border-white/5 group">
                   <div className="w-7 h-7 rounded-full overflow-hidden bg-blue-500">
                    <img src={user.avatar} alt={user.name} className="w-full h-full object-cover" />
                  </div>
                  <span className="text-sm font-semibold max-w-[120px] truncate">{user.name}</span>
                </div>
              )}
            </div>
          </header>

          <div className={`${view === ViewState.LYRICS ? 'p-0 max-w-none' : 'p-6 md:p-10 max-w-6xl mx-auto'} min-h-full transition-all duration-500`}>
            {renderMainContent()}
          </div>
        </main>

        {/* Sidebar DJ also hides in Lyrics view */}
        <aside className={`${view === ViewState.LYRICS ? 'w-0 opacity-0' : 'w-96 opacity-100'} transition-all duration-500 glass border-l border-white/5 p-6 hidden lg:block overflow-hidden`}>
          <GeminiDJ currentTrack={currentTrack} />
        </aside>
      </div>

      <audio ref={audioRef} src={currentTrack.audioUrl} onEnded={nextTrack} crossOrigin="anonymous" />
      <Player 
        currentTrack={currentTrack} 
        isPlaying={isPlaying} 
        onPlayPause={handlePlayPause} 
        onNext={nextTrack} 
        onPrev={prevTrack} 
        onOpenLyrics={() => setView(view === ViewState.LYRICS ? ViewState.HOME : ViewState.LYRICS)}
        audioRef={audioRef} 
        onToggleLike={toggleLike} 
        isLiked={likedTrackIds.has(currentTrack.id)} 
      />
    </div>
  );
};

