                    <Play size={24} fill="black" className="ml-1 text-black" />
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Standard Trending Section */}
      <section className="animate-fade-in">
        <div className="flex justify-between items-end mb-6">
          <div>
            <h2 className="text-2xl font-black font-poppins flex items-center gap-2">
              <TrendingUp className="text-blue-500" size={24} /> 
              {selectedGenre === 'Tất cả' ? 'BXH Xu hướng' : `Đề xuất ${selectedGenre}`}
            </h2>
            <p className="text-sm text-white/40">Giai điệu đang được yêu thích nhất</p>
          </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {getFilteredTracks().slice(0, 6).map((track, idx) => (
            <div 
              key={track.id} 
              onClick={() => handleTrackSelect(track)}
              className="group flex items-center gap-4 p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-blue-500/30 transition-all cursor-pointer relative"
            >
              <div className="relative w-24 h-24 flex-shrink-0">
                <img src={track.coverUrl} className="w-full h-full object-cover rounded-xl shadow-lg" alt={track.title} />
                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center rounded-xl">
                  <Play size={24} fill="white" />
                </div>
                <div className="absolute -top-2 -left-2 w-8 h-8 bg-blue-600 text-white text-[10px] font-black rounded-full flex items-center justify-center border-2 border-[#0a0a0c] shadow-lg">
                  #{idx + 1}
